translated_files.Kernels.cl:
#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define GAMMA 1.4
#define NDIM 3
#define NNB 4
#define VAR_DENSITY 0
#define VAR_MOMENTUM 1
#define VAR_DENSITY_ENERGY (VAR_MOMENTUM+NDIM)
#define NVAR (VAR_DENSITY_ENERGY+1)
#define RK 3
#define smoothing_coefficient 0.2

typedef struct {
    double x;
    double y;
    double z;
} double3;

inline void compute_velocity(double density, double3 momentum, __private double3* velocity) {
    velocity->x = momentum.x / density;
    velocity->y = momentum.y / density;
    velocity->z = momentum.z / density;
}

inline double compute_speed_sqd(double3 velocity) {
    return velocity.x*velocity.x + velocity.y*velocity.y + velocity.z*velocity.z;
}

inline double compute_pressure(double density, double density_energy, double speed_sqd) {
    return (GAMMA - 1.0)*(density_energy - 0.5*density*speed_sqd);
}

inline double compute_speed_of_sound(double density, double pressure) {
    return sqrt(GAMMA * pressure / density);
}

inline void compute_flux_contribution(double density, double3 momentum, double density_energy, double pressure, double3 velocity,
                                      __private double3* fc_momentum_x, __private double3* fc_momentum_y, __private double3* fc_momentum_z, __private double3* fc_density_energy) {
    fc_momentum_x->x = velocity.x * momentum.x + pressure;
    fc_momentum_x->y = velocity.x * momentum.y;
    fc_momentum_x->z = velocity.x * momentum.z;

    fc_momentum_y->x = fc_momentum_x->y;
    fc_momentum_y->y = velocity.y * momentum.y + pressure;
    fc_momentum_y->z = velocity.y * momentum.z;

    fc_momentum_z->x = fc_momentum_x->z;
    fc_momentum_z->y = fc_momentum_y->z;
    fc_momentum_z->z = velocity.z * momentum.z + pressure;

    double de_p = density_energy + pressure;
    fc_density_energy->x = velocity.x * de_p;
    fc_density_energy->y = velocity.y * de_p;
    fc_density_energy->z = velocity.z * de_p;
}

__kernel void initialize_variables(__global double* variables, __global double* ff_variable, int nelr) {
    int i = get_global_id(0);
    if (i >= nelr) return;
    for (int j = 0; j < NVAR; j++) {
        variables[i*NVAR + j] = ff_variable[j];
    }
}

__kernel void compute_step_factor(__global double* variables, __global double* areas, __global double* step_factors, int nelr) {
    int i = get_global_id(0);
    if (i >= nelr) return;

    double density = variables[i*NVAR + VAR_DENSITY];
    double3 momentum;
    momentum.x = variables[i*NVAR + (VAR_MOMENTUM + 0)];
    momentum.y = variables[i*NVAR + (VAR_MOMENTUM + 1)];
    momentum.z = variables[i*NVAR + (VAR_MOMENTUM + 2)];
    double density_energy = variables[i*NVAR + VAR_DENSITY_ENERGY];

    double3 velocity;
    compute_velocity(density, momentum, &velocity);
    double speed_sqd = compute_speed_sqd(velocity);
    double pressure = compute_pressure(density, density_energy, speed_sqd);
    double speed_of_sound = compute_speed_of_sound(density, pressure);

    step_factors[i] = 0.5 / (sqrt(areas[i]) * (sqrt(speed_sqd) + speed_of_sound));
}

__kernel void compute_flux(__global int* elements_surrounding_elements,
                           __global double* normals,
                           __global double* variables,
                           __global double* ff_variable,
                           __global double* fluxes,
                           __global double3* ff_flux_contribution_density_energy,
                           __global double3* ff_flux_contribution_momentum_x,
                           __global double3* ff_flux_contribution_momentum_y,
                           __global double3* ff_flux_contribution_momentum_z,
                           int nelr) {
    int i = get_global_id(0);
    if (i >= nelr) return;

    double3 normal;
    double normal_len;
    double factor;

    double density_i = variables[i*NVAR + VAR_DENSITY];
    double3 momentum_i;
    momentum_i.x = variables[i*NVAR + (VAR_MOMENTUM + 0)];
    momentum_i.y = variables[i*NVAR + (VAR_MOMENTUM + 1)];
    momentum_i.z = variables[i*NVAR + (VAR_MOMENTUM + 2)];
    double density_energy_i = variables[i*NVAR + VAR_DENSITY_ENERGY];

    double3 velocity_i;
    compute_velocity(density_i, momentum_i, &velocity_i);
    double speed_sqd_i = compute_speed_sqd(velocity_i);
    double speed_i = sqrt(speed_sqd_i);
    double pressure_i = compute_pressure(density_i, density_energy_i, speed_sqd_i);
    double speed_of_sound_i = compute_speed_of_sound(density_i, pressure_i);

    double3 flux_contribution_i_momentum_x, flux_contribution_i_momentum_y, flux_contribution_i_momentum_z;
    double3 flux_contribution_i_density_energy;
    compute_flux_contribution(density_i, momentum_i, density_energy_i, pressure_i, velocity_i,
                              &flux_contribution_i_momentum_x, &flux_contribution_i_momentum_y,
                              &flux_contribution_i_momentum_z, &flux_contribution_i_density_energy);

    double flux_i_density = 0.0;
    double3 flux_i_momentum = {0.0, 0.0, 0.0};
    double flux_i_density_energy = 0.0;

    double3 velocity_nb;
    double density_nb, density_energy_nb;
    double3 momentum_nb;
    double3 flux_contribution_nb_momentum_x, flux_contribution_nb_momentum_y, flux_contribution_nb_momentum_z;
    double3 flux_contribution_nb_density_energy;
    double speed_sqd_nb, speed_of_sound_nb, pressure_nb;

    for (int j = 0; j < NNB; j++) {
        int nb = elements_surrounding_elements[i*NNB + j];
        normal.x = normals[(i*NNB + j)*NDIM + 0];
        normal.y = normals[(i*NNB + j)*NDIM + 1];
        normal.z = normals[(i*NNB + j)*NDIM + 2];
        normal_len = sqrt(normal.x*normal.x + normal.y*normal.y + normal.z*normal.z);

        if (nb >= 0) {
            density_nb = variables[nb*NVAR + VAR_DENSITY];
            momentum_nb.x = variables[nb*NVAR + (VAR_MOMENTUM + 0)];
            momentum_nb.y = variables[nb*NVAR + (VAR_MOMENTUM + 1)];
            momentum_nb.z = variables[nb*NVAR + (VAR_MOMENTUM + 2)];
            density_energy_nb = variables[nb*NVAR + VAR_DENSITY_ENERGY];

            compute_velocity(density_nb, momentum_nb, &velocity_nb);
            speed_sqd_nb = compute_speed_sqd(velocity_nb);
            pressure_nb = compute_pressure(density_nb, density_energy_nb, speed_sqd_nb);
            speed_of_sound_nb = compute_speed_of_sound(density_nb, pressure_nb);

            compute_flux_contribution(density_nb, momentum_nb, density_energy_nb, pressure_nb, velocity_nb,
                                      &flux_contribution_nb_momentum_x, &flux_contribution_nb_momentum_y,
                                      &flux_contribution_nb_momentum_z, &flux_contribution_nb_density_energy);

            factor = -normal_len * smoothing_coefficient * 0.5 * (speed_i + sqrt(speed_sqd_nb) + speed_of_sound_i + speed_of_sound_nb);
            flux_i_density += factor * (density_i - density_nb);
            flux_i_density_energy += factor * (density_energy_i - density_energy_nb);
            flux_i_momentum.x += factor * (momentum_i.x - momentum_nb.x);
            flux_i_momentum.y += factor * (momentum_i.y - momentum_nb.y);
            flux_i_momentum.z += factor * (momentum_i.z - momentum_nb.z);

            factor = 0.5 * normal.x;
            flux_i_density += factor * (momentum_nb.x + momentum_i.x);
            flux_i_density_energy += factor * (flux_contribution_nb_density_energy.x + flux_contribution_i_density_energy.x);
            flux_i_momentum.x += factor * (flux_contribution_nb_momentum_x.x + flux_contribution_i_momentum_x.x);
            flux_i_momentum.y += factor * (flux_contribution_nb_momentum_y.x + flux_contribution_i_momentum_y.x);
            flux_i_momentum.z += factor * (flux_contribution_nb_momentum_z.x + flux_contribution_i_momentum_z.x);

            factor = 0.5 * normal.y;
            flux_i_density += factor * (momentum_nb.y + momentum_i.y);
            flux_i_density_energy += factor * (flux_contribution_nb_density_energy.y + flux_contribution_i_density_energy.y);
            flux_i_momentum.x += factor * (flux_contribution_nb_momentum_x.y + flux_contribution_i_momentum_x.y);
            flux_i_momentum.y += factor * (flux_contribution_nb_momentum_y.y + flux_contribution_i_momentum_y.y);
            flux_i_momentum.z += factor * (flux_contribution_nb_momentum_z.y + flux_contribution_i_momentum_z.y);

            factor = 0.5 * normal.z;
            flux_i_density += factor * (momentum_nb.z + momentum_i.z);
            flux_i_density_energy += factor * (flux_contribution_nb_density_energy.z + flux_contribution_i_density_energy.z);
            flux_i_momentum.x += factor * (flux_contribution_nb_momentum_x.z + flux_contribution_i_momentum_x.z);
            flux_i_momentum.y += factor * (flux_contribution_nb_momentum_y.z + flux_contribution_i_momentum_y.z);
            flux_i_momentum.z += factor * (flux_contribution_nb_momentum_z.z + flux_contribution_i_momentum_z.z);
        }
        else if (nb == -1) {
            flux_i_momentum.x += normal.x * pressure_i;
            flux_i_momentum.y += normal.y * pressure_i;
            flux_i_momentum.z += normal.z * pressure_i;
        }
        else if (nb == -2) {
            factor = 0.5 * normal.x;
            flux_i_density += factor * (ff_variable[VAR_MOMENTUM + 0] + momentum_i.x);
            flux_i_density_energy += factor * (ff_flux_contribution_density_energy->x + flux_contribution_i_density_energy.x);
            flux_i_momentum.x += factor * (ff_flux_contribution_momentum_x->x + flux_contribution_i_momentum_x.x);
            flux_i_momentum.y += factor * (ff_flux_contribution_momentum_y->x + flux_contribution_i_momentum_y.x);
            flux_i_momentum.z += factor * (ff_flux_contribution_momentum_z->x + flux_contribution_i_momentum_z.x);

            factor = 0.5 * normal.y;
            flux_i_density += factor * (ff_variable[VAR_MOMENTUM + 1] + momentum_i.y);
            flux_i_density_energy += factor * (ff_flux_contribution_density_energy->y + flux_contribution_i_density_energy.y);
            flux_i_momentum.x += factor * (ff_flux_contribution_momentum_x->y + flux_contribution_i_momentum_x.y);
            flux_i_momentum.y += factor * (ff_flux_contribution_momentum_y->y + flux_contribution_i_momentum_y.y);
            flux_i_momentum.z += factor * (ff_flux_contribution_momentum_z->y + flux_contribution_i_momentum_z.y);

            factor = 0.5 * normal.z;
            flux_i_density += factor * (ff_variable[VAR_MOMENTUM + 2] + momentum_i.z);
            flux_i_density_energy += factor * (ff_flux_contribution_density_energy->z + flux_contribution_i_density_energy.z);
            flux_i_momentum.x += factor * (ff_flux_contribution_momentum_x->z + flux_contribution_i_momentum_x.z);
            flux_i_momentum.y += factor * (ff_flux_contribution_momentum_y->z + flux_contribution_i_momentum_y.z);
            flux_i_momentum.z += factor * (ff_flux_contribution_momentum_z->z + flux_contribution_i_momentum_z.z);
        }
    }

    fluxes[i*NVAR + VAR_DENSITY] = flux_i_density;
    fluxes[i*NVAR + (VAR_MOMENTUM + 0)] = flux_i_momentum.x;
    fluxes[i*NVAR + (VAR_MOMENTUM + 1)] = flux_i_momentum.y;
    fluxes[i*NVAR + (VAR_MOMENTUM + 2)] = flux_i_momentum.z;
    fluxes[i*NVAR + VAR_DENSITY_ENERGY] = flux_i_density_energy;
}

__kernel void time_step(int j, int nelr,
                        __global double* old_variables,
                        __global double* variables,
                        __global double* step_factors,
                        __global double* fluxes) {
    int i = get_global_id(0);
    if (i >= nelr) return;

    double factor = step_factors[i] / (RK + 1 - j);

    variables[i*NVAR + VAR_DENSITY] = old_variables[i*NVAR + VAR_DENSITY] + factor * fluxes[i*NVAR + VAR_DENSITY];
    variables[i*NVAR + VAR_DENSITY_ENERGY] = old_variables[i*NVAR + VAR_DENSITY_ENERGY] + factor * fluxes[i*NVAR + VAR_DENSITY_ENERGY];
    variables[i*NVAR + (VAR_MOMENTUM + 0)] = old_variables[i*NVAR + (VAR_MOMENTUM + 0)] + factor * fluxes[i*NVAR + (VAR_MOMENTUM + 0)];
    variables[i*NVAR + (VAR_MOMENTUM + 1)] = old_variables[i*NVAR + (VAR_MOMENTUM + 1)] + factor * fluxes[i*NVAR + (VAR_MOMENTUM + 1)];
    variables[i*NVAR + (VAR_MOMENTUM + 2)] = old_variables[i*NVAR + (VAR_MOMENTUM + 2)] + factor * fluxes[i*NVAR + (VAR_MOMENTUM + 2)];
}

